mapper.select:
SELECT 
  FROM er.tn_er_vrfr_info v
 WHERE v.er_id   = #{erId}
   AND v.vrfr_sn = #{vrfrSn}
   AND NOW() BETWEEN v.use_bgng_dt AND v.use_end_dt

SELECT COALESCE(MAX(vrfr_sn), 0) + 1
  FROM er.tn_er_vrfr_info
 WHERE er_id = #{erId}

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_er_vrfr_info
 WHERE er_id        = #{erId}
   AND vrfcn_inst_id = #{vrfcnInstId}
   AND vrfr_sn      != #{excludeSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_er_vrfr_info
   SET vrfcn_inst_id    = #{vrfcnInstId},
       cnct_desc        = #{cnctDesc},
       accrd_dtl        = #{accrdDtl},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE er_id   = #{erId}
   AND vrfr_sn = #{vrfrSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_er_vrfr_info
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE er_id   = #{erId}
   AND vrfr_sn = #{vrfrSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
